    const onEdit = vi.fn();
    const onPatternChange = vi.fn();

    render(
      <Patterns
        filterPatterns={['**/*.tmp']}
        newFilterPattern="**/*.cache"
        onAdd={onAdd}
        onDelete={onDelete}
        onEdit={onEdit}
        onPatternChange={onPatternChange}
